function [e1,xMm,yMm,lmbNm,omgFs] = fReadPhicoreH5(fNam,dispL,varargin)%function read phicore e-field file (HDF5)%% [e1,x,y,lmbNm,omgFs] = fReadPhicoreH5(fNam,dispL,figL)%% e1: 3d array of e-filed (y,x,z)% xMm: x [mm] % yMm: y [mm]% lmbNm: wavelength [nm]% omgFs: angular frequency [rad/fs]%% fNam: full path to hdf5 file% dispL: display logig for h5 file tree (1 to show)% varargin{1}: figure handle to display e-field%% Written by Kei Nakamura%% 2018/11/30: created% 2019/4/17: insight%% main body% display hdf5 file treeif dispL==1    h5disp(fNam);    %info = h5info(fNam);endaaa = dir(fNam);fNam2 = aaa.name;if strcmp(fNam2(1:7),'INSIGHT') % insight    ch_xyw = h5read(fNam,'/data/Exyw');  % e-field    xMm = h5read(fNam,'/scales/Exyw_x');   % x [mm], 432    yMm = h5read(fNam,'/scales/Exyw_y');   % y [mm], 465    lmbNm = h5read(fNam,'/scales/Exyw_w');  % wavelength [nm]else % tremites    ch_xyw = h5read(fNam,'/data/ch_xyw');  % e-field    xMm = h5read(fNam,'/scales/ch_xyw_x');   % x [mm], 432    yMm = h5read(fNam,'/scales/ch_xyw_y');   % y [mm], 465    lmbNm = h5read(fNam,'/scales/spectrum_lamb');  % wavelength [nm]endomgFs = ltow(lmbNm);                            % ang-freq [rad/fs]e1 = complex(ch_xyw.r,ch_xyw.i);        % e-field in comprex (73x465x432)e1 = permute(e1,[2,3,1]);   % turn to [y x z] array%% display fieldif nargin==3    labels{1} = 'x [mm]';    labels{2} = 'y [mm]';    labels{3} = 'omega [rad/fs]';    fPlot3DEfld(e1,xMm,yMm,omgFs,labels,varargin{1})end
